{
var bottom = inputs.Length > 0 ? inputs[0] : null;
        var top = inputs.Length > 1 ? inputs[1] : null;
        var mask = inputs.Length > 2 ? inputs[2] : null;
        var size = context.TileSize;

        if (bottom is null && top is null)
            return PixelBuffer.CreateSolid(size, size, 0, 0, 0);
        if (bottom is null)
            return top!.Clone();
        if (top is null)
            return bottom.Clone();

        var mode = GetChoice(parameters, "blendMode", "normal");
        var opacity = GetFloat(parameters, "opacity", 1f);
        var clipToBase = GetBool(parameters, "clipToBase");

        var result = new PixelBuffer(size, size);

        result.ParallelForEachPixel((x, y) =>
        {
            var (br, bg, bb, ba) = bottom.GetPixelWrapped(x, y);
            var (tr, tg, tb, ta) = top.GetPixelWrapped(x, y);

            float blendR, blendG, blendB;
            switch (mode)
            {
                case "multiply":
                    blendR = br * tr;
                    blendG = bg * tg;
                    blendB = bb * tb;
                    break;
                case "screen":
                    blendR = 1f - (1f - br) * (1f - tr);
                    blendG = 1f - (1f - bg) * (1f - tg);
                    blendB = 1f - (1f - bb) * (1f - tb);
                    break;
                case "overlay":
                    blendR = br < 0.5f ? 2f * br * tr : 1f - 2f * (1f - br) * (1f - tr);
                    blendG = bg < 0.5f ? 2f * bg * tg : 1f - 2f * (1f - bg) * (1f - tg);
                    blendB = bb < 0.5f ? 2f * bb * tb : 1f - 2f * (1f - bb) * (1f - tb);
                    break;
                case "softLight":
                    blendR = SoftLight(br, tr);
                    blendG = SoftLight(bg, tg);
                    blendB = SoftLight(bb, tb);
                    break;
                case "hardLight":
                    blendR = tr < 0.5f ? 2f * br * tr : 1f - 2f * (1f - br) * (1f - tr);
                    blendG = tg < 0.5f ? 2f * bg * tg : 1f - 2f * (1f - bg) * (1f - tg);
                    blendB = tb < 0.5f ? 2f * bb * tb : 1f - 2f * (1f - bb) * (1f - tb);
                    break;
                case "difference":
                    blendR = MathF.Abs(br - tr);
                    blendG = MathF.Abs(bg - tg);
                    blendB = MathF.Abs(bb - tb);
                    break;
                case "exclusion":
                    blendR = br + tr - 2f * br * tr;
                    blendG = bg + tg - 2f * bg * tg;
                    blendB = bb + tb - 2f * bb * tb;
                    break;
                case "linearDodge":
                    blendR = Math.Clamp(br + tr, 0f, 1f);
                    blendG = Math.Clamp(bg + tg, 0f, 1f);
                    blendB = Math.Clamp(bb + tb, 0f, 1f);
                    break;
                case "linearBurn":
                    blendR = Math.Clamp(br + tr - 1f, 0f, 1f);
                    blendG = Math.Clamp(bg + tg - 1f, 0f, 1f);
                    blendB = Math.Clamp(bb + tb - 1f, 0f, 1f);
                    break;
                case "colorDodge":
                    blendR = tr < 1f ? Math.Clamp(br / (1f - tr + 0.001f), 0f, 1f) : 1f;
                    blendG = tg < 1f ? Math.Clamp(bg / (1f - tg + 0.001f), 0f, 1f) : 1f;
                    blendB = tb < 1f ? Math.Clamp(bb / (1f - tb + 0.001f), 0f, 1f) : 1f;
                    break;
                case "colorBurn":
                    blendR = tr > 0f ? Math.Clamp(1f - (1f - br) / (tr + 0.001f), 0f, 1f) : 0f;
                    blendG = tg > 0f ? Math.Clamp(1f - (1f - bg) / (tg + 0.001f), 0f, 1f) : 0f;
                    blendB = tb > 0f ? Math.Clamp(1f - (1f - bb) / (tb + 0.001f), 0f, 1f) : 0f;
                    break;
                case "lighter":
                    blendR = MathF.Max(br, tr);
                    blendG = MathF.Max(bg, tg);
                    blendB = MathF.Max(bb, tb);
                    break;
                case "darker":
                    blendR = MathF.Min(br, tr);
                    blendG = MathF.Min(bg, tg);
                    blendB = MathF.Min(bb, tb);
                    break;
                case "hue":
                    {
                        var (bh, bs, bl) = RgbToHsl(br, bg, bb);
                        var (th, _, _) = RgbToHsl(tr, tg, tb);
                        (blendR, blendG, blendB) = HslToRgb(th, bs, bl);
                    }
                    break;
                case "saturation":
                    {
                        var (bh, bs, bl) = RgbToHsl(br, bg, bb);
                        var (_, ts, _) = RgbToHsl(tr, tg, tb);
                        (blendR, blendG, blendB) = HslToRgb(bh, ts, bl);
                    }
                    break;
                case "color":
                    {
                        var (_, _, bl) = RgbToHsl(br, bg, bb);
                        var (th, ts, _) = RgbToHsl(tr, tg, tb);
                        (blendR, blendG, blendB) = HslToRgb(th, ts, bl);
                    }
                    break;
                case "luminosity":
                    {
                        var (bh, bs, _) = RgbToHsl(br, bg, bb);
                        var (_, _, tl) = RgbToHsl(tr, tg, tb);
                        (blendR, blendG, blendB) = HslToRgb(bh, bs, tl);
                    }
                    break;
                case "dissolve":
                    blendR = tr;
                    blendG = tg;
                    blendB = tb;
                    break;
                default: // normal
                    blendR = tr;
                    blendG = tg;
                    blendB = tb;
                    break;
            }

            // Apply mask
            var maskValue = mask is not null ? mask.GetValueWrapped(x, y) : 1f;
            var effectiveOpacity = Math.Clamp(opacity * ta * maskValue, 0f, 1f);

            // Clip to base: only blend where bottom has alpha
            if (clipToBase)
                effectiveOpacity *= ba;

            // Dissolve: dither the opacity per pixel
            if (mode == "dissolve")
                effectiveOpacity = HashToUnit(x, y, 0) < effectiveOpacity ? 1f : 0f;

            var outR = Lerp(br, blendR, effectiveOpacity);
            var outG = Lerp(bg, blendG, effectiveOpacity);
            var outB = Lerp(bb, blendB, effectiveOpacity);
            var outA = clipToBase ? ba : ba + effectiveOpacity * (1f - ba);

            result.SetPixel(x, y,
                Math.Clamp(outR, 0f, 1f),
                Math.Clamp(outG, 0f, 1f),
                Math.Clamp(outB, 0f, 1f),
                Math.Clamp(outA, 0f, 1f));
        });

        return result;


    private static (float h, float s, float l) RgbToHsl(float r, float g, float b)
    {
        var max = MathF.Max(r, MathF.Max(g, b));
        var min = MathF.Min(r, MathF.Min(g, b));
        var delta = max - min;

        var h = 0f;
        var s = 0f;
        var l = (max + min) * 0.5f;

        if (delta > 0.001f)
        {
            s = l <= 0.5f ? delta / (max + min) : delta / (2f - max - min);
            if (MathF.Abs(max - r) < 0.001f)
                h = ((g - b) / delta + (g < b ? 6f : 0f)) * (1f / 6f);
            else if (MathF.Abs(max - g) < 0.001f)
                h = ((b - r) / delta + 2f) * (1f / 6f);
            else
                h = ((r - g) / delta + 4f) * (1f / 6f);
        }

        return (h, s, l);
    }

    private static (float r, float g, float b) HslToRgb(float h, float s, float l)
    {
        if (s < 0.001f)
            return (l, l, l);

        var hue2Rgb = (float p, float q, float t) =>
        {
            if (t < 0f) t += 1f;
            if (t > 1f) t -= 1f;
            if (t < 1f / 6f) return p + (q - p) * 6f * t;
            if (t < 0.5f) return q;
            if (t < 2f / 3f) return p + (q - p) * (2f / 3f - t) * 6f;
            return p;
        };

        var q = l < 0.5f ? l * (1f + s) : l + s - l * s;
        var p = 2f * l - q;

        return (
            hue2Rgb(p, q, h + 1f / 3f),
            hue2Rgb(p, q, h),
            hue2Rgb(p, q, h - 1f / 3f));
    }

    private static float SoftLight(float b, float t)
    {
        if (t <= 0.5f)
            return b - (1f - 2f * t) * b * (1f - b);
        else
            return b + (2f * t - 1f) * (D(b) - b);
    }

    private static float D(float x)
    {
        return x <= 0.25f
            ? ((16f * x - 12f) * x + 4f) * x
            : MathF.Sqrt(x);
    }
}
